  async CountClientsBYMonth(a, b) {
    try {
      if (a == 0 && b == 0) {
        this.chartCountMonth = {
          nonAxisSeries: [a, b, 1],
          colors: ["#0D95BC", "#F36F13", "#413F42"],
          chart: {
            height: 240,
            type: "pie",
          },
          stroke: {
            colors: ["rgba(0,0,0,0)"],
          },
          legend: {
            position: "bottom",
            horizontalAlign: "center",
            fontSize: "15px",
            fontWeight: 550,
            labels: {
              colors: undefined,
              useSeriesColors: true,
            },
            onItemClick: {
              toggleDataSeries: false,
            },
            onItemHover: {
              highlightDataSeries: false,
            },
          },
          dataLabels: {
            enabled: false,
            style: {
              fontSize: "15",
            },
          },
          labels: [" جديد عدد", " تجديد عدد", " لا يوجد بيانات"],
        };
        this.ValidObject[0].CountClientsBYMonthValid = true;
      } else {
        this.chartCountMonth = {
          nonAxisSeries: [a, b],
          colors: ["#0D95BC", "#F36F13"],
          chart: {
            height: 240,
            type: "pie",
          },
          stroke: {
            colors: ["rgba(0,0,0,0)"],
          },
          legend: {
            position: "bottom",
            horizontalAlign: "center",
            fontSize: "15px",
            fontWeight: 550,
            labels: {
              colors: undefined,
              useSeriesColors: true,
            },
            onItemClick: {
              toggleDataSeries: false,
            },
            onItemHover: {
              highlightDataSeries: false,
            },
          },
          dataLabels: {
            enabled: true,
            style: {
              fontSize: "14",
            },
            formatter: function (val, opt) {
              switch (
                opt.seriesIndex // seriesIndex gives the position of slice
              ) {
                case 0:
                  return [
                    formatNumber(Number(a), "en-US", "1.0-0") as string,
                  ] as unknown as string;
                case 1:
                  return [
                    formatNumber(Number(b), "en-US", "1.0-0") as string,
                  ] as unknown as string;
                default:
                  return val as string;
              }
            },
          },
          labels: [" جديد عدد", " تجديد عدد"],
        };
      }
      this.ValidObject[0].CountClientsBYMonthValid = true;
    } catch (error) {
      console.log(error);
    }
  }
