  async GetOfficerInstallmentListDay() {
    if (this.job_code == "-2") {
      let SumOfpaid = 0;
      let SumOfUnpaid = 0;
      this.http
        .post<IOfficerInstallmentList[]>(
          this.env.API_URL + "api/Officer/GetOfficerInstallmentList",
          {
            start_date: this.datepipe.transform(
              this.currentDateTime,
              "yyyy-MM-dd"
            ),
            end_date: this.datepipe.transform(
              this.currentDateTime,
              "yyyy-MM-dd"
            ),
            cur_inst_status: "1,2,3,5,6",
            cur_inst_cond: "0",
            cur_currency_code: "0",
            cur_client_type: "0",
            ls_loan_type: "0",
            all_loan_types: "1",
            ls_funder: "0",
            all_funder: "1",
            cur_officer_key: this.officer_key,
            cur_branch_code: this.branch_code,
          }
        )
        .subscribe({
          next: (data) => {
            this.officerInstallmentListthisDay = data;
            for (let i = 0; i < this.officerInstallmentListthisDay.length; ) {
              if (
                this.officerInstallmentListthisDay[i].inst_status ==
                  "في الخزينة" ||
                this.officerInstallmentListthisDay[i].inst_status ==
                  "لدى بنك خارجي" ||
                this.officerInstallmentListthisDay[i].inst_status == "مسدد جزئي"
              ) {
                SumOfUnpaid += parseInt(
                  this.officerInstallmentListthisDay[i].inst_amount
                );
              }
              if (
                this.officerInstallmentListthisDay[i].inst_status ==
                  "مسدد بالخزينة" ||
                this.officerInstallmentListthisDay[i].inst_status ==
                  "مسدد في بنك خارجي"
              ) {
                SumOfpaid += parseInt(
                  this.officerInstallmentListthisDay[i].inst_amount
                );
              }
              i++;
            }

            this.InstallmentListByDay(SumOfpaid, SumOfUnpaid);
          },
          error: async (err) => {
            await this.alertSerivce.showAlertError(err.error, false);
          },
        });
    } else if (
      this.job_code == "-3" ||
      this.job_code == "-4" ||
      this.job_code == "-5"
    ) {
      this.Officer = this.OfficerForm.value.Officer.toString();
      let SumOfpaid = 0;
      let SumOfUnpaid = 0;
      this.http
        .post<IOfficerInstallmentList[]>(
          this.env.API_URL + "api/Officer/GetOfficerInstallmentList",
          {
            start_date: this.datepipe.transform(
              this.currentDateTime,
              "yyyy-MM-dd"
            ),
            end_date: this.datepipe.transform(
              this.currentDateTime,
              "yyyy-MM-dd"
            ),
            cur_inst_status: "1,2,3,5,6",
            cur_inst_cond: "0",
            cur_currency_code: "0",
            cur_client_type: "0",
            ls_loan_type: "0",
            all_loan_types: "1",
            ls_funder: "0",
            all_funder: "1",
            cur_officer_key: this.Officer,
            cur_branch_code: this.branch_code,
          }
        )
        .subscribe({
          next: (data) => {
            this.officerInstallmentListthisDay = data;
            if (data.length == 0) {
              this.InstallmentListByDay(0, 0);
            } else {
              for (let i = 0; i < this.officerInstallmentListthisDay.length; ) {
                if (
                  this.officerInstallmentListthisDay[i].inst_status ==
                    "في الخزينة" ||
                  this.officerInstallmentListthisDay[i].inst_status ==
                    "لدى بنك خارجي" ||
                  this.officerInstallmentListthisDay[i].inst_status ==
                    "مسدد جزئي"
                ) {
                  SumOfUnpaid += parseInt(
                    this.officerInstallmentListthisDay[i].inst_amount
                  );
                }
                if (
                  this.officerInstallmentListthisDay[i].inst_status ==
                    "مسدد بالخزينة" ||
                  this.officerInstallmentListthisDay[i].inst_status ==
                    "مسدد في بنك خارجي"
                ) {
                  SumOfpaid += parseInt(
                    this.officerInstallmentListthisDay[i].inst_amount
                  );
                }

                i++;
              }
              this.InstallmentListByDay(SumOfpaid, SumOfUnpaid);
            }
          },
          error: async (err) => {
            await this.alertSerivce.showAlertError(err.error, false);
          },
        });
    }
  }
